#include <stdio.h>
#include <stdlib.h>
#define MOD 30041975

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, K;
        scanf("%d %d", &N, &K);
        long long dp[N][N];
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < N; j++) {
                dp[i][j] = 0;
            }
        }
        dp[0][0] = 1;
        for (int i = 1; i < N; i++) {
            for (int j = 0; j <= i; j++) {
                for (int k = 0; k < i; k++) {
                    dp[i][j] = (dp[i][j] + dp[k][j - 1]) % MOD;
                }
            }
        }
        long long ans = 0;
        for (int i = K; i < N; i++) {
            ans = (ans + dp[N - 1][i]) % MOD;
        }
        printf("%lld\n", ans);
    }
    return 0;
}

